TRUNCATE offers, compatibilities, supersessions, part_references, parts, sellers, categories, manufacturers RESTART IDENTITY CASCADE;

SELECT pg_catalog.setval('public.categories_id_seq', 12, true);
SELECT pg_catalog.setval('public.compatibilities_id_seq', 2, true);
SELECT pg_catalog.setval('public.manufacturers_id_seq', 9, true);
SELECT pg_catalog.setval('public.offers_id_seq', 53, true);
SELECT pg_catalog.setval('public.part_references_id_seq', 5, true);
SELECT pg_catalog.setval('public.parts_id_seq', 25, true);
SELECT pg_catalog.setval('public.sellers_id_seq', 7, true);
SELECT pg_catalog.setval('public.supersessions_id_seq', 4, true);
